SELECT COUNT(1)
FROM cart_item
WHERE user_id = #{userId}
  AND product_id = #{productId}
  AND ((sku_id IS NULL AND #{skuId} IS NULL) OR sku_id = #{skuId})

SELECT *
FROM cart_item
WHERE user_id = #{userId}
  AND product_id = #{productId}
  AND ((sku_id IS NULL AND #{skuId} IS NULL) OR sku_id = #{skuId})
LIMIT 1
